import React from 'react';
import Massages from '../Content/Massages/Massages';
import Dialog from './Dialog/Dialog';
import Mass from './Mass/Mass';
import s from './NavMassage.module.css'

const NavMassage = () => {
    
    let DialogData =[
        {id: 1, name:"Misha"},
        {id: 2, name:"Vika Nine 22"},
        {id: 3, name:"Sinfozatron"},
        {id: 4, name:"Dasha Nine 2"}
    ]

    return (
        <div className={s.navmassage} >
            <div className={s.dialog}>
                <Dialog name={DialogData[0].name} id={DialogData[0].id} />
                <Dialog name={DialogData[1].name} id={DialogData[1].id} />
                <Dialog name={DialogData[2].name} id={DialogData[2].id} />
                <Dialog name={DialogData[3].name} id={DialogData[3].id} />
            </div>
            <div>
                <Mass message='Привет' />
                <Mass message='Игореккак дела?' />
                <Mass message='В качалку гоним к 12.00' />
                <Mass message='Молчишь-в жопе торчишь' />
            </div>
        </div>
    )
}
export default NavMassage;
